import * as S from "fp-ts/State";
import { pipe } from "fp-ts/function";

type AST =
  | { readonly kind: "lit"; readonly n: number }
  | { readonly kind: "add"; readonly l: AST; readonly r: AST };

interface Gen { readonly next: number; readonly code: ReadonlyArray<string> }

const emit = (line: string): S.State<Gen, void> => (g) => [
  undefined,
  { next: g.next, code: [...g.code, line] },
];
const fresh: S.State<Gen, number> = (g) => [g.next, { next: g.next + 1, code: g.code }];

export const compile = (ast: AST): S.State<Gen, void> => {
  if (ast.kind === "lit") return emit(`PUSH ${ast.n}`);
  return pipe(
    compile(ast.l),
    S.chain(() => compile(ast.r)),
    S.chain(() => fresh),
    S.chain((id) => emit(`ADD #${id}`)),
  );
};

export const sample: AST = { kind: "add", l: { kind: "lit", n: 1 }, r: { kind: "lit", n: 2 } };
export const out = compile(sample)({ next: 0, code: [] });
