```typescript
import * as O from "fp-ts/Option";
import * as E from "fp-ts/Either";
import { pipe } from "fp-ts/function";

export const flip = <Err, A>(
  x: E.Either<Err, O.Option<A>>,
): O.Option<E.Either<Err, A>> =>
  pipe(
    x,
    E.match<Err, O.Option<A>, O.Option<E.Either<Err, A>>>(
      (e) => O.some(E.left(e)),
      (oa) => pipe(oa, O.map((a) => E.right(a))),
    ),
  );

export const a = flip(E.right(O.some(1))); // some(right(1))
export const b = flip(E.right(O.none)); // none
export const c = flip(E.left("boom")); // some(left("boom"))
```

