import * as E from "fp-ts/Either";
import { pipe } from "fp-ts/function";

export const mapInner = <Err, A, B>(
  x: O.Option<E.Either<Err, A>>,
  f: (a: A) => B,
): O.Option<E.Either<Err, B>> =>
  pipe(x, O.map(E.map(f)));

export const demo = mapInner(O.some(E.right(10)), (n) => n + 1);
```

