import * as RA from "fp-ts/ReadonlyArray";
import * as R from "fp-ts/Record";
import * as TE from "fp-ts/TaskEither";
import { pipe } from "fp-ts/function";

interface User { readonly id: string; readonly name: string }

declare const lookup: (id: string) => TE.TaskEither<string, User>;

export const fetchAll = (
  ids: ReadonlyArray<string>,
): TE.TaskEither<string, { readonly count: number; readonly byId: Record<string, User> }> =>
  pipe(
    ids,
    RA.traverse(TE.ApplicativePar)(lookup),
    TE.map((users) => ({
      count: users.length,
      byId: pipe(
        users,
        RA.reduce<User, Record<string, User>>({}, (acc, u) => ({ ...acc, [u.id]: u })),
      ),
    })),
    TE.map(({ count, byId }) => ({ count, byId: pipe(byId, R.map((u) => u)) })),
  );
