import * as E from "fp-ts/Either";
import * as RA from "fp-ts/ReadonlyArray";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { getSemigroup } from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";

const V = E.getApplicativeValidation(getSemigroup<string>());

const checkAge = (row: { readonly age: number }, i: number): E.Either<RNEA.ReadonlyNonEmptyArray<string>, number> => {
  if (!Number.isFinite(row.age)) return E.left([`row ${i}: not finite`]);
  if (row.age < 0) return E.left([`row ${i}: negative age`]);
  return E.right(row.age);
};

export const validateAll = (
  rows: ReadonlyArray<{ readonly age: number }>,
): E.Either<RNEA.ReadonlyNonEmptyArray<string>, ReadonlyArray<number>> =>
  pipe(
    rows,
    RA.traverseWithIndex(V)((i, row) => checkAge(row, i)),
  );

export const ok = validateAll([{ age: 1 }, { age: 2 }]);
export const bad = validateAll([{ age: -1 }, { age: NaN }, { age: 5 }]);
